contracts/SwarmAgentRegistryLink.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/access/Ownable.sol";

/**
 * @title SwarmAgentRegistryLink
 * @notice Agent registry on Ethereum Sepolia with ASN identity and credit scoring.
 *         Mirrors the Hedera AgentRegistry but adds on-chain ASN + credit fields.
 */
contract SwarmAgentRegistryLink is Ownable {
    struct Agent {
        address agentAddress;
        string name;
        string skills;
        string asn;
        uint256 feeRate;
        uint16 creditScore;
        uint8 trustScore;
        bool active;
        uint256 registeredAt;
    }

    mapping(address => Agent) public agents;
    address[] public agentList;
    mapping(string => address) public asnToAgent;

    event AgentRegistered(address indexed agentAddress, string name, string asn, uint256 timestamp);
    event AgentDeactivated(address indexed agentAddress, uint256 timestamp);
    event SkillsUpdated(address indexed agentAddress, string newSkills, uint256 timestamp);
    event CreditUpdated(address indexed agentAddress, uint16 creditScore, uint8 trustScore, uint256 timestamp);

    constructor() Ownable(msg.sender) {}

    function registerAgent(
        string calldata name,
        string calldata skills,
        string calldata asn,
        uint256 feeRate
    ) external {
        require(!agents[msg.sender].active, "Already registered");
        require(bytes(asn).length > 0, "ASN required");
        require(asnToAgent[asn] == address(0), "ASN already taken");

        agents[msg.sender] = Agent({
            agentAddress: msg.sender,
            name: name,
            skills: skills,
            asn: asn,
            feeRate: feeRate,
            creditScore: 680,
            trustScore: 50,
            active: true,
            registeredAt: block.timestamp
        });

        agentList.push(msg.sender);
        asnToAgent[asn] = msg.sender;

        emit AgentRegistered(msg.sender, name, asn, block.timestamp);
    }

    function registerAgentFor(
        address agentAddr,
        string calldata name,
        string calldata skills,
        string calldata asn,
        uint256 feeRate
    ) external onlyOwner {
        require(!agents[agentAddr].active, "Already registered");
        require(bytes(asn).length > 0, "ASN required");
        require(asnToAgent[asn] == address(0), "ASN already taken");

        agents[agentAddr] = Agent({
            agentAddress: agentAddr,
            name: name,
            skills: skills,
            asn: asn,
            feeRate: feeRate,
            creditScore: 680,
            trustScore: 50,
            active: true,
            registeredAt: block.timestamp
        });

        agentList.push(agentAddr);
        asnToAgent[asn] = agentAddr;

        emit AgentRegistered(agentAddr, name, asn, block.timestamp);
    }

    function updateSkills(string calldata newSkills) external {
        require(agents[msg.sender].active, "Not registered");
        agents[msg.sender].skills = newSkills;
        emit SkillsUpdated(msg.sender, newSkills, block.timestamp);
    }

    function updateCredit(
        address agentAddr,
        uint16 creditScore,
        uint8 trustScore
    ) external onlyOwner {
        require(agents[agentAddr].active, "Not registered");
        require(creditScore >= 300 && creditScore <= 900, "Credit 300-900");
        require(trustScore <= 100, "Trust 0-100");

        agents[agentAddr].creditScore = creditScore;
        agents[agentAddr].trustScore = trustScore;

        emit CreditUpdated(agentAddr, creditScore, trustScore, block.timestamp);
    }

    function deactivateAgent() external {
        require(agents[msg.sender].active, "Not registered");
        agents[msg.sender].active = false;
        emit AgentDeactivated(msg.sender, block.timestamp);
    }

    function getAgent(address agentAddr) external view returns (Agent memory) {
        return agents[agentAddr];
    }

    function getAgentByASN(string calldata asn) external view returns (Agent memory) {
        address addr = asnToAgent[asn];
        require(addr != address(0), "ASN not found");
        return agents[addr];
    }

    function isRegistered(address agentAddr) external view returns (bool) {
        return agents[agentAddr].active;
    }

    function agentCount() external view returns (uint256) {
        return agentList.length;
    }

    function getAllAgents() external view returns (Agent[] memory) {
        Agent[] memory result = new Agent[](agentList.length);
        for (uint256 i = 0; i < agentList.length; i++) {
            result[i] = agents[agentList[i]];
        }
        return result;
    }
}

contracts/SwarmASNRegistry.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/access/Ownable.sol";

/**
 * @title SwarmASNRegistry
 * @notice On-chain Agent Social Number (ASN) identity + credit registry.
 *         Stores ASN records, credit scores, and task completion history.
 *         Format: ASN-SWM-YYYY-HHHH-HHHH-CC
 */
contract SwarmASNRegistry is Ownable {
    struct ASNRecord {
        string asn;
        address owner;
        string agentName;
        string agentType;
        uint16 creditScore;
        uint8 trustScore;
        uint256 tasksCompleted;
        uint256 totalVolumeWei;
        uint256 registeredAt;
        uint256 lastActive;
        bool active;
    }

    mapping(string => ASNRecord) public records;
    mapping(address => string) public ownerToASN;
    string[] public allASNs;

    event ASNRegistered(string asn, address indexed owner, string agentName, uint256 timestamp);
    event CreditUpdated(string asn, uint16 creditScore, uint8 trustScore, uint256 timestamp);
    event TaskCompleted(string asn, uint256 newTotal, uint256 volume, uint256 timestamp);

    constructor() Ownable(msg.sender) {}

    function registerASN(
        string calldata asn,
        string calldata agentName,
        string calldata agentType
    ) external {
        require(bytes(asn).length > 0, "ASN required");
        require(records[asn].owner == address(0), "ASN already registered");
        require(bytes(ownerToASN[msg.sender]).length == 0, "Address already has ASN");

        records[asn] = ASNRecord({
            asn: asn,
            owner: msg.sender,
            agentName: agentName,
            agentType: agentType,
            creditScore: 680,
            trustScore: 50,
            tasksCompleted: 0,
            totalVolumeWei: 0,
            registeredAt: block.timestamp,
            lastActive: block.timestamp,
            active: true
        });

        ownerToASN[msg.sender] = asn;
        allASNs.push(asn);

        emit ASNRegistered(asn, msg.sender, agentName, block.timestamp);
    }

    function registerASNFor(
        address owner,
        string calldata asn,
        string calldata agentName,
        string calldata agentType
    ) external onlyOwner {
        require(bytes(asn).length > 0, "ASN required");
        require(records[asn].owner == address(0), "ASN already registered");
        require(bytes(ownerToASN[owner]).length == 0, "Address already has ASN");

        records[asn] = ASNRecord({
            asn: asn,
            owner: owner,
            agentName: agentName,
            agentType: agentType,
            creditScore: 680,
            trustScore: 50,
            tasksCompleted: 0,
            totalVolumeWei: 0,
            registeredAt: block.timestamp,
            lastActive: block.timestamp,
            active: true
        });

        ownerToASN[owner] = asn;
        allASNs.push(asn);

        emit ASNRegistered(asn, owner, agentName, block.timestamp);
    }

    function updateCredit(
        string calldata asn,
        uint16 creditScore,
        uint8 trustScore
    ) external onlyOwner {
        require(records[asn].active, "ASN not active");
        require(creditScore >= 300 && creditScore <= 900, "Credit 300-900");
        require(trustScore <= 100, "Trust 0-100");

        records[asn].creditScore = creditScore;
        records[asn].trustScore = trustScore;
        records[asn].lastActive = block.timestamp;

        emit CreditUpdated(asn, creditScore, trustScore, block.timestamp);
    }

    function recordTaskCompletion(
        string calldata asn,
        uint256 volumeWei
    ) external onlyOwner {
        require(records[asn].active, "ASN not active");

        records[asn].tasksCompleted += 1;
        records[asn].totalVolumeWei += volumeWei;
        records[asn].lastActive = block.timestamp;

        emit TaskCompleted(asn, records[asn].tasksCompleted, volumeWei, block.timestamp);
    }

    function getRecord(string calldata asn) external view returns (ASNRecord memory) {
        return records[asn];
    }

    function getRecordByOwner(address owner) external view returns (ASNRecord memory) {
        string memory asn = ownerToASN[owner];
        require(bytes(asn).length > 0, "No ASN for address");
        return records[asn];
    }

    function totalRecords() external view returns (uint256) {
        return allASNs.length;
    }

    function getAllRecords() external view returns (ASNRecord[] memory) {
        ASNRecord[] memory result = new ASNRecord[](allASNs.length);
        for (uint256 i = 0; i < allASNs.length; i++) {
            result[i] = records[allASNs[i]];
        }
        return result;
    }
}

contracts/SwarmTaskBoardLink.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";

/**
 * @title SwarmTaskBoardLink
 * @notice Task board on Ethereum Sepolia using LINK ERC-20 for payments.
 *         Mirrors the Hedera TaskBoard but replaces native msg.value with
 *         LINK token approve() + transferFrom() pattern.
 */
contract SwarmTaskBoardLink is Ownable {
    using SafeERC20 for IERC20;

    IERC20 public immutable linkToken;

    enum TaskStatus { Open, Claimed, Completed, Expired, Disputed }

    struct Task {
        uint256 taskId;
        address vault;
        string title;
        string description;
        string requiredSkills;
        uint256 deadline;
        uint256 budget;
        address poster;
        address claimedBy;
        bytes32 deliveryHash;
        uint256 createdAt;
        uint8 status;
    }

    Task[] public tasks;

    event TaskPosted(uint256 indexed taskId, address indexed poster, address vault, string title, uint256 budget, uint256 deadline, uint256 timestamp);
    event TaskClaimed(uint256 indexed taskId, address indexed agent, uint256 timestamp);
    event DeliverySubmitted(uint256 indexed taskId, address indexed agent, bytes32 deliveryHash, uint256 timestamp);
    event DeliveryApproved(uint256 indexed taskId, address indexed agent, uint256 payout, uint256 timestamp);
    event DeliveryDisputed(uint256 indexed taskId, address indexed poster, uint256 timestamp);

    constructor(address _linkToken) Ownable(msg.sender) {
        require(_linkToken != address(0), "Invalid LINK address");
        linkToken = IERC20(_linkToken);
    }

    /**
     * @notice Post a new task. Caller must approve() LINK first.
     * @param vault The vault address associated with the task
     * @param title Task title
     * @param description Task description
     * @param requiredSkills Comma-separated required skills
     * @param deadline Unix timestamp deadline
     * @param budgetLink Budget in LINK (18 decimals)
     */
    function postTask(
        address vault,
        string calldata title,
        string calldata description,
        string calldata requiredSkills,
        uint256 deadline,
        uint256 budgetLink
    ) external {
        require(budgetLink > 0, "Budget must be > 0");
        require(deadline > block.timestamp, "Deadline must be in the future");

        linkToken.safeTransferFrom(msg.sender, address(this), budgetLink);

        uint256 taskId = tasks.length;
        tasks.push(Task({
            taskId: taskId,
            vault: vault,
            title: title,
            description: description,
            requiredSkills: requiredSkills,
            deadline: deadline,
            budget: budgetLink,
            poster: msg.sender,
            claimedBy: address(0),
            deliveryHash: bytes32(0),
            createdAt: block.timestamp,
            status: uint8(TaskStatus.Open)
        }));

        emit TaskPosted(taskId, msg.sender, vault, title, budgetLink, deadline, block.timestamp);
    }

    function claimTask(uint256 taskId) external {
        require(taskId < tasks.length, "Invalid task");
        Task storage task = tasks[taskId];
        require(task.status == uint8(TaskStatus.Open), "Not open");
        require(task.deadline > block.timestamp, "Expired");
        require(task.poster != msg.sender, "Cannot claim own task");

        task.claimedBy = msg.sender;
        task.status = uint8(TaskStatus.Claimed);

        emit TaskClaimed(taskId, msg.sender, block.timestamp);
    }

    function submitDelivery(uint256 taskId, bytes32 deliveryHash) external {
        require(taskId < tasks.length, "Invalid task");
        Task storage task = tasks[taskId];
        require(task.status == uint8(TaskStatus.Claimed), "Not claimed");
        require(task.claimedBy == msg.sender, "Not assigned agent");

        task.deliveryHash = deliveryHash;

        emit DeliverySubmitted(taskId, msg.sender, deliveryHash, block.timestamp);
    }

    function approveDelivery(uint256 taskId) external {
        require(taskId < tasks.length, "Invalid task");
        Task storage task = tasks[taskId];
        require(task.status == uint8(TaskStatus.Claimed), "Not claimed");
        require(task.poster == msg.sender, "Only poster can approve");
        require(task.deliveryHash != bytes32(0), "No delivery submitted");

        task.status = uint8(TaskStatus.Completed);

        linkToken.safeTransfer(task.claimedBy, task.budget);

        emit DeliveryApproved(taskId, task.claimedBy, task.budget, block.timestamp);
    }

    function disputeDelivery(uint256 taskId) external {
        require(taskId < tasks.length, "Invalid task");
        Task storage task = tasks[taskId];
        require(task.status == uint8(TaskStatus.Claimed), "Not claimed");
        require(task.poster == msg.sender, "Only poster can dispute");

        task.status = uint8(TaskStatus.Disputed);

        emit DeliveryDisputed(taskId, msg.sender, block.timestamp);
    }

    function getTask(uint256 taskId) external view returns (Task memory) {
        require(taskId < tasks.length, "Invalid task");
        return tasks[taskId];
    }

    function getAllTasks() external view returns (Task[] memory) {
        return tasks;
    }

    function getOpenTasks() external view returns (Task[] memory) {
        uint256 count = 0;
        for (uint256 i = 0; i < tasks.length; i++) {
            if (tasks[i].status == uint8(TaskStatus.Open) && tasks[i].deadline > block.timestamp) {
                count++;
            }
        }

        Task[] memory result = new Task[](count);
        uint256 idx = 0;
        for (uint256 i = 0; i < tasks.length; i++) {
            if (tasks[i].status == uint8(TaskStatus.Open) && tasks[i].deadline > block.timestamp) {
                result[idx++] = tasks[i];
            }
        }
        return result;
    }

    function taskCount() external view returns (uint256) {
        return tasks.length;
    }
}

contracts/SwarmTreasuryLink.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";

/**
 * @title SwarmTreasuryLink
 * @notice Treasury contract tracking LINK token balances.
 *         Mirrors the Hedera AgentTreasury but uses LINK ERC-20.
 *         Revenue is split into compute, growth, and reserve buckets.
 */
contract SwarmTreasuryLink is Ownable {
    using SafeERC20 for IERC20;

    IERC20 public immutable linkToken;

    uint256 public totalRevenue;
    uint256 public computeBalance;
    uint256 public growthBalance;
    uint256 public reserveBalance;
    address public agentAddress;

    // Revenue split: 50% compute, 30% growth, 20% reserve
    uint256 public constant COMPUTE_BPS = 5000;
    uint256 public constant GROWTH_BPS = 3000;
    uint256 public constant RESERVE_BPS = 2000;

    event RevenueDeposited(address indexed from, uint256 amount, uint256 timestamp);
    event Withdrawn(address indexed to, uint256 amount, uint256 timestamp);
    event AgentAddressUpdated(address indexed newAgent, uint256 timestamp);

    constructor(address _linkToken) Ownable(msg.sender) {
        require(_linkToken != address(0), "Invalid LINK address");
        linkToken = IERC20(_linkToken);
    }

    function setAgentAddress(address _agentAddress) external onlyOwner {
        agentAddress = _agentAddress;
        emit AgentAddressUpdated(_agentAddress, block.timestamp);
    }

    /**
     * @notice Deposit LINK revenue. Caller must approve() first.
     * @param amount Amount of LINK to deposit (18 decimals)
     */
    function depositRevenue(uint256 amount) external {
        require(amount > 0, "Amount must be > 0");

        linkToken.safeTransferFrom(msg.sender, address(this), amount);

        uint256 computeShare = (amount * COMPUTE_BPS) / 10000;
        uint256 growthShare = (amount * GROWTH_BPS) / 10000;
        uint256 reserveShare = amount - computeShare - growthShare;

        totalRevenue += amount;
        computeBalance += computeShare;
        growthBalance += growthShare;
        reserveBalance += reserveShare;

        emit RevenueDeposited(msg.sender, amount, block.timestamp);
    }

    function getPnL() external view returns (
        uint256 _totalRevenue,
        uint256 _computeBalance,
        uint256 _growthBalance,
        uint256 _reserveBalance
    ) {
        return (totalRevenue, computeBalance, growthBalance, reserveBalance);
    }

    function withdraw(address to, uint256 amount) external onlyOwner {
        require(to != address(0), "Invalid address");
        uint256 contractBalance = linkToken.balanceOf(address(this));
        require(amount <= contractBalance, "Insufficient balance");

        linkToken.safeTransfer(to, amount);

        emit Withdrawn(to, amount, block.timestamp);
    }
}

